class Solution {
public:
    int getKth(int lo, int hi, int k) {
        vector<pair<int, int>> power;
        for (int i = lo; i <= hi; ++i) {
            power.push_back({i, calculatePower(i)});
        }
        sort(power.begin(), power.end(), [](const pair<int, int>& a, const pair<int, int>& b) {
            return a.second == b.second ? a.first < b.first : a.second < b.second;
        });
        return power[k - 1].first;
    }

    int calculatePower(int x) {
        int steps = 0;
        while (x != 1) {
            if (x % 2 == 0) {
                x /= 2;
            } else {
                x = 3 * x + 1;
            }
            ++steps;
        }
        return steps;
    }
};
